};

import React from 'react';
import { Play, Pause, Signal } from 'lucide-react';
import { Station } from '../types';

interface StationCardProps {
  station: Station;
  isPlaying: boolean;
  isCurrent: boolean;
  onPlay: (station: Station) => void;
}

export const StationCard: React.FC<StationCardProps> = ({ station, isPlaying, isCurrent, onPlay }) => {
  return (
    <div 
      className="group relative bg-slate-800/50 hover:bg-slate-800 rounded-2xl p-4 transition-all duration-300 hover:shadow-xl border border-white/5 hover:border-white/10"
    >
      <div className="relative aspect-square rounded-xl overflow-hidden mb-4 shadow-lg">
        <img 
          src={station.coverUrl} 
          alt={station.name} 
          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
        />

        {/* Hover Overlay / Active State */}
        <div className={`absolute inset-0 bg-black/40 flex items-center justify-center transition-opacity duration-300 ${isCurrent ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
          <button 
            onClick={() => onPlay(station)}
            className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-black shadow-xl hover:scale-105 transition-transform"
          >
            {isCurrent && isPlaying ? (
              <Pause size={24} fill="currentColor" />
            ) : (
              <Play size={24} fill="currentColor" className="ml-1" />
            )}
          </button>
        </div>

        {isCurrent && isPlaying && (
          <div className="absolute bottom-2 right-2 bg-violet-600 text-white text-[10px] font-bold px-2 py-1 rounded-full flex items-center gap-1 animate-pulse">
            <Signal size={10} />
            LIVE
          </div>
        )}
      </div>

      <div>
        <h3 className={`font-bold text-lg leading-tight truncate ${isCurrent ? 'text-violet-400' : 'text-white'}`}>
          {station.name}
        </h3>
        <p className="text-slate-400 text-sm mt-1 truncate">{station.description}</p>

        <div className="flex flex-wrap gap-2 mt-3">
          {station.tags.slice(0, 2).map(tag => (
            <span key={tag} className="text-[10px] uppercase font-semibold bg-slate-700/50 text-slate-400 px-2 py-1 rounded-md">
              {tag}
            </span>
          ))}
          {station.frequency && (
             <span className="text-[10px] uppercase font-semibold border border-slate-700 text-slate-500 px-2 py-1 rounded-md ml-auto">
             {station.frequency}
           </span>
          )}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Play, Pause, SkipBack, SkipForward, Volume2, VolumeX, List, Radio } from 'lucide-react';
import { Station } from '../types';

interface PlayerBarProps {
  currentStation: Station | null;
  isPlaying: boolean;
  onTogglePlay: () => void;
  volume: number;
  onVolumeChange: (val: number) => void;
  onToggleMute: () => void;
  isMuted: boolean;
  onNext: () => void;
  onPrev: () => void;
  togglePlaylist: () => void;
  showPlaylist: boolean;
}

export const PlayerBar: React.FC<PlayerBarProps> = ({
  currentStation,
  isPlaying,
  onTogglePlay,
  volume,
  onVolumeChange,
  onToggleMute,
  isMuted,
  onNext,
  onPrev,
  togglePlaylist,
  showPlaylist
}) => {
  if (!currentStation) {
    return (
      <div className="h-24 bg-slate-900 border-t border-slate-800 flex items-center justify-center text-slate-500">
        <Radio className="mr-2 animate-pulse" /> 选择一个电台开始收听
      </div>
    );
  }

  return (
    <div className="h-24 bg-slate-900/95 backdrop-blur-md border-t border-slate-800 text-white px-4 md:px-8 grid grid-cols-1 md:grid-cols-3 items-center z-50 fixed bottom-0 left-0 right-0">
      {/* Track Info */}
      <div className="flex items-center gap-4">
        <img 
          src={currentStation.coverUrl} 
          alt={currentStation.name} 
          className={`w-14 h-14 rounded-lg shadow-lg object-cover ${isPlaying ? 'animate-spin-slow' : ''}`}
          style={{ animationDuration: '10s' }}
        />
        <div className="overflow-hidden">
          <h4 className="font-bold truncate">{currentStation.name}</h4>
          <p className="text-sm text-slate-400 truncate">{currentStation.description}</p>
        </div>
      </div>

      {/* Controls */}
      <div className="flex flex-col items-center justify-center gap-2">
        <div className="flex items-center gap-6">
          <button onClick={onPrev} className="text-slate-400 hover:text-white transition-colors">
            <SkipBack size={20} />
          </button>

          <button 
            onClick={onTogglePlay}
            className="w-12 h-12 bg-white text-black rounded-full flex items-center justify-center hover:scale-105 transition-transform shadow-lg shadow-white/10"
          >
            {isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" className="ml-1" />}
          </button>

          <button onClick={onNext} className="text-slate-400 hover:text-white transition-colors">
            <SkipForward size={20} />
          </button>
        </div>

        {/* Progress Bar (Visual Only for Live Radio usually, but we simulate a "Live" indicator) */}
        <div className="w-full max-w-xs flex items-center gap-2 text-xs text-slate-500 font-mono">
          <span className="text-violet-400 flex items-center gap-1">
             <span className="relative flex h-2 w-2">
              <span className={`animate-ping absolute inline-flex h-full w-full rounded-full bg-violet-400 opacity-75 ${isPlaying ? '' : 'hidden'}`}></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-violet-500"></span>
            </span>
            LIVE
          </span>
          <div className="h-1 flex-1 bg-slate-800 rounded-full overflow-hidden">
             <div className="h-full bg-gradient-to-r from-violet-500 to-fuchsia-500 w-full animate-pulse"></div>
          </div>
          <span>{currentStation.frequency || 'WEB'}</span>
        </div>
      </div>

      {/* Volume & Playlist Toggle */}
      <div className="hidden md:flex items-center justify-end gap-4">
        <div className="flex items-center gap-2 group">
          <button onClick={onToggleMute} className="text-slate-400 group-hover:text-white">
            {isMuted || volume === 0 ? <VolumeX size={20} /> : <Volume2 size={20} />}
          </button>
          <input
            type="range"
            min="0"
            max="1"
            step="0.01"
            value={isMuted ? 0 : volume}
            onChange={(e) => onVolumeChange(parseFloat(e.target.value))}
            className="w-24 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:rounded-full hover:[&::-webkit-slider-thumb]:scale-125 transition-all"
          />
        </div>

        <button 
          onClick={togglePlaylist}
          className={`p-2 rounded-lg transition-colors ${showPlaylist ? 'bg-violet-500/20 text-violet-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
        >
          <List size={20} />
        </button>
      </div>
    </div>
  );
};

import React from 'react';
import { X, Play, BarChart2 } from 'lucide-react';
import { Station } from '../types';

interface PlaylistProps {
  isOpen: boolean;
  onClose: () => void;
  stations: Station[];
  currentStation: Station | null;
  onPlay: (station: Station) => void;
  isPlaying: boolean;
}

export const Playlist: React.FC<PlaylistProps> = ({ 
  isOpen, 
  onClose, 
  stations, 
  currentStation, 
  onPlay,
  isPlaying 
}) => {
  return (
    <div 
      className={`fixed inset-y-0 right-0 w-80 bg-slate-900 border-l border-slate-800 shadow-2xl transform transition-transform duration-300 ease-in-out z-40 pt-20 md:pt-0 ${
        isOpen ? 'translate-x-0' : 'translate-x-full'
      }`}
    >
      <div className="flex items-center justify-between p-4 border-b border-slate-800">
        <h2 className="text-lg font-bold text-white flex items-center gap-2">
          <span className="text-violet-500">播放列表</span>
          <span className="text-xs font-normal text-slate-500 bg-slate-800 px-2 py-0.5 rounded-full">{stations.length}</span>
        </h2>
        <button onClick={onClose} className="text-slate-400 hover:text-white p-1 rounded-full hover:bg-slate-800">
          <X size={20} />
        </button>
      </div>

      <div className="overflow-y-auto h-[calc(100vh-140px)] p-2 space-y-1">
        {stations.map((station) => {
          const isActive = currentStation?.id === station.id;
          return (
            <div 
              key={station.id}
              onClick={() => onPlay(station)}
              className={`group flex items-center gap-3 p-2 rounded-lg cursor-pointer transition-colors ${
                isActive ? 'bg-slate-800' : 'hover:bg-slate-800/50'
              }`}
            >
              <div className="relative w-10 h-10 flex-shrink-0">
                <img 
                  src={station.coverUrl} 
                  alt={station.name} 
                  className={`w-full h-full rounded object-cover ${isActive && isPlaying ? 'opacity-50' : ''}`} 
                />
                {isActive && isPlaying && (
                  <div className="absolute inset-0 flex items-center justify-center">
                    <BarChart2 size={16} className="text-violet-400 animate-pulse" />
                  </div>
                )}
                <div className={`absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 ${isActive ? 'hidden' : ''}`}>
                  <Play size={16} className="text-white" fill="currentColor" />
                </div>
              </div>

              <div className="min-w-0 flex-1">
                <h4 className={`text-sm font-medium truncate ${isActive ? 'text-violet-400' : 'text-slate-200'}`}>
                  {station.name}
                </h4>
                <div className="flex items-center justify-between text-xs text-slate-500 mt-0.5">
                  <span className="truncate max-w-[100px]">{station.category}</span>
                  <span>{station.frequency}</span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Sidebar } from './components/Sidebar';
import { StationCard } from './components/StationCard';
import { PlayerBar } from './components/PlayerBar';
import { Playlist } from './components/Playlist';
import { STATIONS, CATEGORIES } from './constants';
import { Station } from './types';
import { Search, Bell, Menu } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [activeTab, setActiveTab] = useState('discover');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [stations] = useState<Station[]>(STATIONS);
  const [currentStation, setCurrentStation] = useState<Station | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.7);
  const [isMuted, setIsMuted] = useState(false);
  const [showPlaylist, setShowPlaylist] = useState(false);
  const [showMobileMenu, setShowMobileMenu] = useState(false);

  // Audio Ref
  const audioRef = useRef<HTMLAudioElement>(null);

  // Effects
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  useEffect(() => {
    if (currentStation && audioRef.current) {
      if (isPlaying) {
        // In a real app, you'd handle loading states and promise rejections
        const playPromise = audioRef.current.play();
        if (playPromise !== undefined) {
          playPromise.catch(error => {
            console.error("Audio playback failed:", error);
            setIsPlaying(false);
          });
        }
      } else {
        audioRef.current.pause();
      }
    }
  }, [currentStation, isPlaying]);

  // Handlers
  const handlePlayStation = (station: Station) => {
    if (currentStation?.id === station.id) {
      setIsPlaying(!isPlaying);
    } else {
      setCurrentStation(station);
      setIsPlaying(true);
    }
  };

  const handleNext = () => {
    if (!currentStation) return;
    const currentIndex = stations.findIndex(s => s.id === currentStation.id);
    const nextIndex = (currentIndex + 1) % stations.length;
    handlePlayStation(stations[nextIndex]);
  };

  const handlePrev = () => {
    if (!currentStation) return;
    const currentIndex = stations.findIndex(s => s.id === currentStation.id);
    const prevIndex = (currentIndex - 1 + stations.length) % stations.length;
    handlePlayStation(stations[prevIndex]);
  };

  // Filter Logic
  const filteredStations = stations.filter(station => {
    if (selectedCategory !== 'all' && station.category !== selectedCategory) return false;
    return true;
  });

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden font-sans">
      {/* Hidden Audio Element */}
      <audio 
        ref={audioRef} 
        src={currentStation?.streamUrl} 
        onEnded={() => setIsPlaying(false)}
        onError={() => {
            console.error("Stream error");
            setIsPlaying(false);
            alert("模拟流媒体连接失败或已离线");
        }}
      />

      {/* Mobile Sidebar Overlay */}
      {showMobileMenu && (
        <div className="fixed inset-0 bg-black/80 z-40 md:hidden" onClick={() => setShowMobileMenu(false)} />
      )}

      {/* Sidebar (Responsive) */}
      <div className={`fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 md:relative md:translate-x-0 ${showMobileMenu ? 'translate-x-0' : '-translate-x-full'}`}>
        <Sidebar activeTab={activeTab} setActiveTab={(tab) => { setActiveTab(tab); setShowMobileMenu(false); }} />
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative">
        {/* Header */}
        <header className="flex items-center justify-between px-6 py-4 bg-slate-950/50 backdrop-blur-sm z-10 sticky top-0">
          <div className="flex items-center gap-4">
            <button className="md:hidden text-slate-300" onClick={() => setShowMobileMenu(true)}>
              <Menu size={24} />
            </button>
            <div className="relative hidden sm:block">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 w-4 h-4" />
              <input 
                type="text" 
                placeholder="搜索电台、节目..." 
                className="bg-slate-900 border border-slate-800 rounded-full pl-10 pr-4 py-2 text-sm text-slate-300 focus:outline-none focus:border-violet-500 focus:ring-1 focus:ring-violet-500 w-64 transition-all"
              />
            </div>
          </div>
          <div className="flex items-center gap-4">
             <button className="relative text-slate-400 hover:text-white transition-colors">
               <Bell size={20} />
               <span className="absolute top-0 right-0 w-2 h-2 bg-red-500 rounded-full"></span>
             </button>
             <div className="w-8 h-8 rounded-full bg-slate-700 overflow-hidden border border-slate-600">
               <img src="https://picsum.photos/100/100" alt="User" />
             </div>
          </div>
        </header>

        {/* Scrollable Area */}
        <main className="flex-1 overflow-y-auto p-6 pb-32 scrollbar-hide">
          {activeTab === 'discover' ? (
            <>
              {/* Hero / Featured */}
              <div className="mb-8 p-8 rounded-3xl bg-gradient-to-r from-violet-600 to-indigo-600 text-white relative overflow-hidden shadow-2xl">
                 <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -translate-y-1/2 translate-x-1/4 blur-3xl"></div>
                 <div className="relative z-10 max-w-lg">
                    <span className="inline-block px-3 py-1 bg-white/20 backdrop-blur-md rounded-full text-xs font-bold mb-4 border border-white/10">今日推荐</span>
                    <h2 className="text-4xl font-bold mb-2">城市晚高峰</h2>
                    <p className="text-violet-100 mb-6 text-lg">最好的音乐陪伴你的归途，实时路况与好歌同行。</p>
                    <button 
                      onClick={() => handlePlayStation(stations[0])}
                      className="bg-white text-violet-700 px-6 py-3 rounded-full font-bold hover:bg-slate-100 transition-colors flex items-center gap-2 shadow-lg"
                    >
                      <Menu className="w-4 h-4 rotate-90" /> 立即收听
                    </button>
                 </div>
              </div>

              {/* Categories */}
              <div className="mb-8">
                <div className="flex items-center gap-3 overflow-x-auto pb-2 scrollbar-hide">
                  {CATEGORIES.map(cat => (
                    <button
                      key={cat.id}
                      onClick={() => setSelectedCategory(cat.id)}
                      className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all border ${
                        selectedCategory === cat.id
                          ? 'bg-white text-slate-900 border-white'
                          : 'bg-slate-900 text-slate-400 border-slate-800 hover:border-slate-600 hover:text-white'
                      }`}
                    >
                      {cat.name}
                    </button>
                  ))}
                </div>
              </div>

              {/* Station Grid */}
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredStations.map(station => (
                  <StationCard
                    key={station.id}
                    station={station}
                    isPlaying={currentStation?.id === station.id && isPlaying}
                    isCurrent={currentStation?.id === station.id}
                    onPlay={handlePlayStation}
                  />
                ))}
                {filteredStations.length === 0 && (
                  <div className="col-span-full py-20 text-center text-slate-500">
                    没有找到该分类下的电台
                  </div>
                )}
              </div>
            </>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-500">
              <div className="bg-slate-900 p-6 rounded-full mb-4">
                <Menu size={48} className="opacity-20" />
              </div>
              <h3 className="text-xl font-medium text-slate-400 mb-2">即将推出</h3>
              <p>该功能正在开发中...</p>
            </div>
          )}
        </main>

        {/* Playlist Sidebar (Overlay) */}
        <Playlist 
          isOpen={showPlaylist}
          onClose={() => setShowPlaylist(false)}
          stations={stations}
          currentStation={currentStation}
          onPlay={handlePlayStation}
          isPlaying={isPlaying}
        />

        {/* Player Bar */}
        <PlayerBar 
          currentStation={currentStation}
          isPlaying={isPlaying}
          onTogglePlay={() => setIsPlaying(!isPlaying)}
          volume={volume}
          onVolumeChange={setVolume}
          isMuted={isMuted}
          onToggleMute={() => setIsMuted(!isMuted)}
          onNext={handleNext}
          onPrev={handlePrev}
          togglePlaylist={() => setShowPlaylist(!showPlaylist)}
          showPlaylist={showPlaylist}
        />
      </div>
    </div>
  );
};

export default App;

