};

import React, { useState, useRef, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { StationCard } from './components/StationCard';
import { PlayerBar } from './components/PlayerBar';
import { Playlist } from './components/Playlist';
import { BottomNav } from './components/BottomNav';
import { MobileFullPlayer } from './components/MobileFullPlayer';
import { STATIONS, CATEGORIES } from './constants';
import { Station } from './types';
import { Search, Bell, Menu } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [activeTab, setActiveTab] = useState('discover');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [stations] = useState<Station[]>(STATIONS);
  const [currentStation, setCurrentStation] = useState<Station | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.7);
  const [isMuted, setIsMuted] = useState(false);
  const [showPlaylist, setShowPlaylist] = useState(false);
  const [showFullPlayer, setShowFullPlayer] = useState(false);
  const [showMobileSidebar, setShowMobileSidebar] = useState(false);

  // Audio Ref
  const audioRef = useRef<HTMLAudioElement>(null);

  // Effects
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  useEffect(() => {
    if (currentStation && audioRef.current) {
      if (isPlaying) {
        // In a real app, you'd handle loading states and promise rejections
        const playPromise = audioRef.current.play();
        if (playPromise !== undefined) {
          playPromise.catch(error => {
            console.error("Audio playback failed:", error);
            setIsPlaying(false);
          });
        }
      } else {
        audioRef.current.pause();
      }
    }
  }, [currentStation, isPlaying]);

  // Handlers
  const handlePlayStation = (station: Station) => {
    if (currentStation?.id === station.id) {
      setIsPlaying(!isPlaying);
    } else {
      setCurrentStation(station);
      setIsPlaying(true);
    }
  };

  const handleNext = () => {
    if (!currentStation) return;
    const currentIndex = stations.findIndex(s => s.id === currentStation.id);
    const nextIndex = (currentIndex + 1) % stations.length;
    handlePlayStation(stations[nextIndex]);
  };

  const handlePrev = () => {
    if (!currentStation) return;
    const currentIndex = stations.findIndex(s => s.id === currentStation.id);
    const prevIndex = (currentIndex - 1 + stations.length) % stations.length;
    handlePlayStation(stations[prevIndex]);
  };

  // Filter Logic
  const filteredStations = stations.filter(station => {
    if (selectedCategory !== 'all' && station.category !== selectedCategory) return false;
    return true;
  });

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden font-sans">
      {/* Hidden Audio Element */}
      <audio 
        ref={audioRef} 
        src={currentStation?.streamUrl} 
        onEnded={() => setIsPlaying(false)}
        onError={() => {
            console.error("Stream error");
            setIsPlaying(false);
            // alert("模拟流媒体连接失败或已离线");
        }}
      />

      {/* Mobile Sidebar (Optional/Secondary) */}
      {showMobileSidebar && (
        <div className="fixed inset-0 bg-black/80 z-50 md:hidden" onClick={() => setShowMobileSidebar(false)}>
           <div className="w-64 h-full bg-slate-900" onClick={e => e.stopPropagation()}>
             <Sidebar activeTab={activeTab} setActiveTab={(tab) => { setActiveTab(tab); setShowMobileSidebar(false); }} />
           </div>
        </div>
      )}

      {/* Sidebar (Desktop) */}
      <div className="hidden md:block fixed inset-y-0 left-0 z-40">
        <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative md:pl-64">
        {/* Header */}
        <header className="flex items-center justify-between px-4 md:px-6 py-4 bg-slate-950/50 backdrop-blur-sm z-10 sticky top-0">
          <div className="flex items-center gap-4">
            {/* Show Logo on mobile since Sidebar is hidden */}
            <div className="md:hidden flex items-center gap-2">
                <div className="w-8 h-8 bg-gradient-to-tr from-violet-500 to-fuchsia-500 rounded-lg flex items-center justify-center">
                    {/* Simple Radio Icon */}
                    <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5.636 18.364a9 9 0 010-12.728m12.728 0a9 9 0 010 12.728m-9.9-2.829a5 5 0 010-7.07m7.072 0a5 5 0 010 7.07M9 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                </div>
                <span className="font-bold text-lg">RadioZen</span>
            </div>

            <div className="relative hidden sm:block">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 w-4 h-4" />
              <input 
                type="text" 
                placeholder="搜索电台、节目..." 
                className="bg-slate-900 border border-slate-800 rounded-full pl-10 pr-4 py-2 text-sm text-slate-300 focus:outline-none focus:border-violet-500 focus:ring-1 focus:ring-violet-500 w-64 transition-all"
              />
            </div>
          </div>
          <div className="flex items-center gap-4">
             <button className="relative text-slate-400 hover:text-white transition-colors">
               <Bell size={20} />
               <span className="absolute top-0 right-0 w-2 h-2 bg-red-500 rounded-full"></span>
             </button>
             <button 
              onClick={() => setShowMobileSidebar(true)}
              className="md:hidden w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center border border-slate-700"
             >
               <Menu size={18} />
             </button>
             <div className="hidden md:block w-8 h-8 rounded-full bg-slate-700 overflow-hidden border border-slate-600">
               <img src="https://picsum.photos/100/100" alt="User" />
             </div>
          </div>
        </header>

        {/* Scrollable Area */}
        <main className="flex-1 overflow-y-auto p-4 md:p-6 pb-32 md:pb-32 scrollbar-hide">
          {activeTab === 'discover' ? (
            <>
              {/* Hero / Featured */}
              <div className="mb-8 p-6 md:p-8 rounded-3xl bg-gradient-to-r from-violet-600 to-indigo-600 text-white relative overflow-hidden shadow-2xl">
                 <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -translate-y-1/2 translate-x-1/4 blur-3xl"></div>
                 <div className="relative z-10 max-w-lg">
                    <span className="inline-block px-3 py-1 bg-white/20 backdrop-blur-md rounded-full text-xs font-bold mb-4 border border-white/10">今日推荐</span>
                    <h2 className="text-3xl md:text-4xl font-bold mb-2">城市晚高峰</h2>
                    <p className="text-violet-100 mb-6 text-sm md:text-lg">最好的音乐陪伴你的归途，实时路况与好歌同行。</p>
                    <button 
                      onClick={() => handlePlayStation(stations[0])}
                      className="bg-white text-violet-700 px-6 py-3 rounded-full font-bold hover:bg-slate-100 transition-colors flex items-center gap-2 shadow-lg text-sm md:text-base"
                    >
                      <Menu className="w-4 h-4 rotate-90" /> 立即收听
                    </button>
                 </div>
              </div>

              {/* Categories */}
              <div className="mb-8">
                <div className="flex items-center gap-3 overflow-x-auto pb-2 scrollbar-hide">
                  {CATEGORIES.map(cat => (
                    <button
                      key={cat.id}
                      onClick={() => setSelectedCategory(cat.id)}
                      className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all border ${
                        selectedCategory === cat.id
                          ? 'bg-white text-slate-900 border-white'
                          : 'bg-slate-900 text-slate-400 border-slate-800 hover:border-slate-600 hover:text-white'
                      }`}
                    >
                      {cat.name}
                    </button>
                  ))}
                </div>
              </div>

              {/* Station Grid */}
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-6">
                {filteredStations.map(station => (
                  <StationCard
                    key={station.id}
                    station={station}
                    isPlaying={currentStation?.id === station.id && isPlaying}
                    isCurrent={currentStation?.id === station.id}
                    onPlay={handlePlayStation}
                  />
                ))}
                {filteredStations.length === 0 && (
                  <div className="col-span-full py-20 text-center text-slate-500">
                    没有找到该分类下的电台
                  </div>
                )}
              </div>
            </>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-500">
              <div className="bg-slate-900 p-6 rounded-full mb-4">
                <Menu size={48} className="opacity-20" />
              </div>
              <h3 className="text-xl font-medium text-slate-400 mb-2">即将推出</h3>
              <p>该功能正在开发中...</p>
            </div>
          )}
        </main>

        {/* Playlist Sidebar (Overlay) */}
        <Playlist 
          isOpen={showPlaylist}
          onClose={() => setShowPlaylist(false)}
          stations={stations}
          currentStation={currentStation}
          onPlay={handlePlayStation}
          isPlaying={isPlaying}
        />

        {/* Player Bar (Mini Player on Mobile) */}
        <PlayerBar 
          currentStation={currentStation}
          isPlaying={isPlaying}
          onTogglePlay={() => setIsPlaying(!isPlaying)}
          volume={volume}
          onVolumeChange={setVolume}
          isMuted={isMuted}
          onToggleMute={() => setIsMuted(!isMuted)}
          onNext={handleNext}
          onPrev={handlePrev}
          togglePlaylist={() => setShowPlaylist(!showPlaylist)}
          showPlaylist={showPlaylist}
          onOpenFullPlayer={() => setShowFullPlayer(true)}
        />

        {/* Bottom Nav (Mobile Only) */}
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />

        {/* Full Screen Player (Mobile Only) */}
        {showFullPlayer && (
          <MobileFullPlayer 
            station={currentStation}
            isPlaying={isPlaying}
            onTogglePlay={() => setIsPlaying(!isPlaying)}
            onClose={() => setShowFullPlayer(false)}
            onNext={handleNext}
            onPrev={handlePrev}
            volume={volume}
            onVolumeChange={setVolume}
          />
        )}
      </div>
    </div>
  );
};

export default App;

