import React, { useState, useRef, useEffect } from 'react';
import Hls from 'hls.js';
import { Sidebar } from './components/Sidebar';
import { StationCard } from './components/StationCard';
import { PlayerBar } from './components/PlayerBar';
import { Playlist } from './components/Playlist';
import { BottomNav } from './components/BottomNav';
import { MobileFullPlayer } from './components/MobileFullPlayer';
import { StationDetail } from './components/StationDetail';
import { ProfileView } from './components/ProfileView';
import { SettingsView } from './components/SettingsView';
import { STATIONS, CATEGORIES } from './constants';
import { Station } from './types';
import { Search, Bell, Menu, Heart, History, X } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [activeTab, setActiveTab] = useState('discover');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isMobileSearchOpen, setIsMobileSearchOpen] = useState(false);
  const [stations] = useState<Station[]>(STATIONS);

  // Playlist State
  const [playlist, setPlaylist] = useState<Station[]>([]);
  // 'all' means playing from the main list/grid. 'playlist' means playing from the user queue.
  const [playContext, setPlayContext] = useState<'all' | 'playlist'>('all');

  const [currentStation, setCurrentStation] = useState<Station | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.7);
  const [isMuted, setIsMuted] = useState(false);
  const [showPlaylist, setShowPlaylist] = useState(false);
  const [showFullPlayer, setShowFullPlayer] = useState(false);
  const [showMobileSidebar, setShowMobileSidebar] = useState(false);
  const [detailViewStation, setDetailViewStation] = useState<Station | null>(null);
  const [favorites, setFavorites] = useState<string[]>([]);

  // Recent Stations State
  const [recentStationIds, setRecentStationIds] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('recentStations');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load recent stations", e);
      return [];
    }
  });

  // Refs
  const audioRef = useRef<HTMLAudioElement>(null);
  const hlsRef = useRef<Hls | null>(null);

  // Effect: Volume control
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  // Effect: Switch to discover tab when searching
  useEffect(() => {
    if (searchQuery.trim()) {
      setActiveTab('discover');
    }
  }, [searchQuery]);

  // Effect: Handle Source Loading (Normal vs HLS)
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !currentStation) return;

    const src = currentStation.streamUrl;
    const isM3u8 = src.includes('.m3u8') || src.includes('application/x-mpegurl');

    // Clean up previous HLS instance
    if (hlsRef.current) {
      hlsRef.current.destroy();
      hlsRef.current = null;
    }

    if (isM3u8 && Hls.isSupported()) {
      const hls = new Hls({
        enableWorker: true,
        lowLatencyMode: true,
        // Increase timeout settings for slow connections
        manifestLoadingTimeOut: 20000,
        manifestLoadingMaxRetry: 3,
        levelLoadingTimeOut: 20000,
        levelLoadingMaxRetry: 3,
      });
      hlsRef.current = hls;

      hls.loadSource(src);
      hls.attachMedia(audio);

      hls.on(Hls.Events.MANIFEST_PARSED, () => {
        if (isPlaying) {
          const playPromise = audio.play();
          if (playPromise !== undefined) {
             playPromise.catch(error => {
                if (error.name === 'AbortError') return;
                console.error("HLS Auto-play failed:", error);
                setIsPlaying(false);
             });
          }
        }
      });

      hls.on(Hls.Events.ERROR, (event, data) => {
        if (data.fatal) {
          switch (data.type) {
            case Hls.ErrorTypes.NETWORK_ERROR:
              console.error("HLS Network error details:", data);
              // Try to recover network error
              console.log("Attempting to recover from network error...");
              hls.startLoad();
              break;
            case Hls.ErrorTypes.MEDIA_ERROR:
              console.warn("HLS Media error, recovering...");
              hls.recoverMediaError();
              break;
            default:
              console.error("HLS Fatal error, destroying...", data);
              hls.destroy();
              setIsPlaying(false);
              break;
          }
        } else {
            // Non-fatal errors (often minor network hiccups)
            console.log("HLS non-fatal error:", data.type, data);
        }
      });
    } else {
      // Native Audio (MP3 or Native HLS on Safari)
      audio.src = src;
      audio.load();
      if (isPlaying) {
        const playPromise = audio.play();
        if (playPromise !== undefined) {
           playPromise.catch(error => {
              if (error.name === 'AbortError') return;
              console.error("Playback failed:", error);
              setIsPlaying(false);
           });
        }
      }
    }

    // Cleanup when component unmounts or station changes
    return () => {
      if (hlsRef.current) {
        hlsRef.current.destroy();
        hlsRef.current = null;
      }
    };
  }, [currentStation?.id]); // Only change source if station ID changes

  // Effect: Handle Play/Pause toggling
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !currentStation) return;

    if (isPlaying) {
      if (audio.paused) {
        const playPromise = audio.play();
        if (playPromise !== undefined) {
          playPromise.catch(error => {
            if (error.name === 'AbortError') return;
            console.error("Play toggle failed:", error);
          });
        }
      }
    } else {
      if (!audio.paused) {
        audio.pause();
      }
    }
  }, [isPlaying]);


  // --- Handlers ---

  const addToRecent = (station: Station) => {
    setRecentStationIds(prev => {
      const newRecents = [station.id, ...prev.filter(id => id !== station.id)].slice(0, 20);
      try {
        localStorage.setItem('recentStations', JSON.stringify(newRecents));
      } catch (e) {
        console.error("Failed to save recent stations", e);
      }
      return newRecents;
    });
  };

  const handlePlayStation = (station: Station, context: 'all' | 'playlist' = 'all') => {
    setPlayContext(context);

    if (currentStation?.id === station.id) {
      setIsPlaying(!isPlaying);
    } else {
      setCurrentStation(station);
      setIsPlaying(true);
      addToRecent(station);
    }
  };

  const handleNext = () => {
    if (!currentStation) return;

    let listToUse = stations;
    if (playContext === 'playlist' && playlist.length > 0) {
      listToUse = playlist;
    }

    const currentIndex = listToUse.findIndex(s => s.id === currentStation.id);
    // If not found (e.g. removed from playlist while playing), default to 0
    const nextIndex = currentIndex === -1 ? 0 : (currentIndex + 1) % listToUse.length;

    const nextStation = listToUse[nextIndex];
    setCurrentStation(nextStation);
    setIsPlaying(true);
    addToRecent(nextStation);
  };

  const handlePrev = () => {
    if (!currentStation) return;

    let listToUse = stations;
    if (playContext === 'playlist' && playlist.length > 0) {
      listToUse = playlist;
    }

    const currentIndex = listToUse.findIndex(s => s.id === currentStation.id);
    const prevIndex = currentIndex === -1 ? 0 : (currentIndex - 1 + listToUse.length) % listToUse.length;

    const prevStation = listToUse[prevIndex];
    setCurrentStation(prevStation);
    setIsPlaying(true);
    addToRecent(prevStation);
  };

  // Playlist Management
  const handleAddToPlaylist = (station: Station) => {
    setPlaylist(prev => {
      if (prev.some(s => s.id === station.id)) {
        return prev; 
      }
      return [...prev, station];
    });
    setShowPlaylist(true);
  };

  const handleRemoveFromPlaylist = (id: string) => {
    setPlaylist(prev => prev.filter(s => s.id !== id));
  };


  const handleStationClick = (station: Station) => {
    setDetailViewStation(station);
  };

  const handleBackToDiscover = () => {
    setDetailViewStation(null);
  };

  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    setDetailViewStation(null);
    setShowMobileSidebar(false);
  };

  const handleTagClick = (tag: string) => {
    setSelectedTag(tag);
    setActiveTab('discover');
    setDetailViewStation(null);
    setSearchQuery('');
    setSelectedCategory('all');
  };

  const toggleFavorite = (id: string) => {
    setFavorites(prev => prev.includes(id) ? prev.filter(pid => pid !== id) : [...prev, id]);
  };

  // Derived Data
  const filteredStations = stations.filter(station => {
    // 1. Filter by Category
    if (selectedCategory !== 'all' && station.category !== selectedCategory) return false;

    // 2. Filter by Tag
    if (selectedTag && !station.tags.includes(selectedTag)) return false;

    // 3. Filter by Search Query
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase().trim();
      const matchesName = station.name.toLowerCase().includes(query);
      const matchesDesc = station.description.toLowerCase().includes(query);
      const matchesTags = station.tags.some(tag => tag.toLowerCase().includes(query));

      return matchesName || matchesDesc || matchesTags;
    }

    return true;
  });

  const favoriteStations = stations.filter(s => favorites.includes(s.id));

  const recentStations = recentStationIds
    .map(id => stations.find(s => s.id === id))
    .filter((s): s is Station => !!s);

  // Helper for rendering content based on activeTab
  const renderContent = () => {
    if (detailViewStation) {
      return (
        <StationDetail 
          station={detailViewStation} 
          isPlaying={currentStation?.id === detailViewStation.id && isPlaying}
          onTogglePlay={() => handlePlayStation(detailViewStation, 'all')}
          onAddToPlaylist={handleAddToPlaylist}
          onBack={handleBackToDiscover}
          onTagClick={handleTagClick}
        />
      );
    }

    switch (activeTab) {
      case 'discover':
        return (
            <>
              {/* Hero / Featured - Hide if searching or filtering by tag */}
              {!searchQuery && !selectedTag && (
                <div className="mb-8 p-6 md:p-8 rounded-3xl bg-gradient-to-r from-violet-600 to-indigo-600 text-white relative overflow-hidden shadow-2xl">
                   <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -translate-y-1/2 translate-x-1/4 blur-3xl"></div>
                   <div className="relative z-10 max-w-lg">
                      <span className="inline-block px-3 py-1 bg-white/20 backdrop-blur-md rounded-full text-xs font-bold mb-4 border border-white/10">今日推荐</span>
                      <h2 className="text-3xl md:text-4xl font-bold mb-2">城市晚高峰</h2>
                      <p className="text-violet-100 mb-6 text-sm md:text-lg">最好的音乐陪伴你的归途，实时路况与好歌同行。</p>
                      <button 
                        onClick={() => handlePlayStation(stations[0], 'all')}
                        className="bg-white text-violet-700 px-6 py-3 rounded-full font-bold hover:bg-slate-100 transition-colors flex items-center gap-2 shadow-lg text-sm md:text-base"
                      >
                        <Menu className="w-4 h-4 rotate-90" /> 立即收听
                      </button>
                   </div>
                </div>
              )}

              {/* Categories */}
              <div className="mb-8">
                <div className="flex items-center gap-3 overflow-x-auto pb-2 scrollbar-hide">
                  {CATEGORIES.map(cat => (
                    <button
                      key={cat.id}
                      onClick={() => { setSelectedCategory(cat.id); setSelectedTag(null); }}
                      className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all border ${
                        selectedCategory === cat.id && !selectedTag
                          ? 'bg-white text-slate-900 border-white'
                          : 'bg-slate-900 text-slate-400 border-slate-800 hover:border-slate-600 hover:text-white'
                      }`}
                    >
                      {cat.name}
                    </button>
                  ))}
                </div>
              </div>

              {/* Tag Filter Indicator */}
              {selectedTag && (
                <div className="flex items-center gap-2 mb-6 animate-in fade-in slide-in-from-left-2">
                  <span className="text-slate-400 text-sm">正在浏览标签:</span>
                  <button 
                    onClick={() => setSelectedTag(null)}
                    className="flex items-center gap-1 px-3 py-1 bg-violet-600 text-white rounded-full text-sm font-medium hover:bg-violet-700 transition-colors"
                  >
                    #{selectedTag} <X size={14} />
                  </button>
                </div>
              )}

              {/* Station Grid */}
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-6">
                {filteredStations.map(station => (
                  <StationCard
                    key={station.id}
                    station={station}
                    isPlaying={currentStation?.id === station.id && isPlaying}
                    isCurrent={currentStation?.id === station.id}
                    isFavorite={favorites.includes(station.id)}
                    onPlay={(s) => handlePlayStation(s, 'all')}
                    onClick={handleStationClick}
                    onToggleFavorite={toggleFavorite}
                    onAddToPlaylist={handleAddToPlaylist}
                    onTagClick={handleTagClick}
                  />
                ))}
                {filteredStations.length === 0 && (
                  <div className="col-span-full py-20 text-center text-slate-500">
                    {searchQuery ? (
                        <>
                            <p className="text-lg text-slate-400 mb-2">没有找到与 "{searchQuery}" 相关的电台</p>
                            <button onClick={() => setSearchQuery('')} className="text-violet-400 hover:underline">清除搜索</button>
                        </>
                    ) : selectedTag ? (
                         <>
                            <p className="text-lg text-slate-400 mb-2">没有找到标签为 "#{selectedTag}" 的电台</p>
                            <button onClick={() => setSelectedTag(null)} className="text-violet-400 hover:underline">查看全部</button>
                        </>
                    ) : (
                        "没有找到该分类下的电台"
                    )}
                  </div>
                )}
              </div>
            </>
        );
      case 'favorites':
        return (
            <div className="pb-10">
              <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
                 <Heart className="text-rose-500 fill-rose-500" /> 我的收藏
              </h2>
              {favoriteStations.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-6">
                  {favoriteStations.map(station => (
                    <StationCard
                      key={station.id}
                      station={station}
                      isPlaying={currentStation?.id === station.id && isPlaying}
                      isCurrent={currentStation?.id === station.id}
                      isFavorite={true}
                      onPlay={(s) => handlePlayStation(s, 'all')}
                      onClick={handleStationClick}
                      onToggleFavorite={toggleFavorite}
                      onAddToPlaylist={handleAddToPlaylist}
                      onTagClick={handleTagClick}
                    />
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-20 text-slate-500">
                   <div className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mb-4">
                     <Heart size={32} className="opacity-20" />
                   </div>
                   <p className="text-lg">暂无收藏电台</p>
                   <button onClick={() => setActiveTab('discover')} className="mt-4 px-6 py-2 bg-violet-600/10 text-violet-400 rounded-full text-sm font-medium hover:bg-violet-600/20 transition-colors">
                       去发现更多
                   </button>
                </div>
              )}
            </div>
        );
      case 'recent':
        return (
            <div className="pb-10">
              <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
                 <History className="text-slate-100" /> 最近播放
              </h2>
              {recentStations.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-6">
                  {recentStations.map(station => (
                    <StationCard
                      key={station.id}
                      station={station}
                      isPlaying={currentStation?.id === station.id && isPlaying}
                      isCurrent={currentStation?.id === station.id}
                      isFavorite={favorites.includes(station.id)}
                      onPlay={(s) => handlePlayStation(s, 'all')}
                      onClick={handleStationClick}
                      onToggleFavorite={toggleFavorite}
                      onAddToPlaylist={handleAddToPlaylist}
                      onTagClick={handleTagClick}
                    />
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-20 text-slate-500">
                   <div className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mb-4">
                     <History size={32} className="opacity-20" />
                   </div>
                   <p className="text-lg">暂无最近播放记录</p>
                   <button onClick={() => setActiveTab('discover')} className="mt-4 px-6 py-2 bg-violet-600/10 text-violet-400 rounded-full text-sm font-medium hover:bg-violet-600/20 transition-colors">
                       去听听看
                   </button>
                </div>
              )}
            </div>
        );
      case 'profile':
        return <ProfileView onNavigate={setActiveTab} />;
      case 'settings':
        return <SettingsView />;
      default:
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-500">
              <div className="bg-slate-900 p-6 rounded-full mb-4">
                <Menu size={48} className="opacity-20" />
              </div>
              <h3 className="text-xl font-medium text-slate-400 mb-2">即将推出</h3>
              <p>该功能正在开发中...</p>
            </div>
        );
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden font-sans">
      {/* Hidden Audio Element - Remove src prop as it's handled in useEffect */}
      <audio 
        ref={audioRef} 
        onEnded={handleNext} // Auto-play next when stream/track ends (mostly for mp3 files)
        onError={(e) => {
            console.error("Native Audio Error", e);
            if (!hlsRef.current) {
               setIsPlaying(false);
            }
        }}
      />

      {/* Mobile Sidebar (Optional/Secondary) */}
      {showMobileSidebar && (
        <div className="fixed inset-0 bg-black/80 z-50 md:hidden" onClick={() => setShowMobileSidebar(false)}>
           <div className="w-64 h-full bg-slate-900" onClick={e => e.stopPropagation()}>
             <Sidebar activeTab={activeTab} setActiveTab={handleTabChange} />
           </div>
        </div>
      )}

      {/* Sidebar (Desktop) */}
      <div className="hidden md:block fixed inset-y-0 left-0 z-40">
        <Sidebar activeTab={activeTab} setActiveTab={handleTabChange} />
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative md:pl-64">
        {/* Header */}
        <header className="flex items-center justify-between px-4 md:px-6 py-4 bg-slate-950/50 backdrop-blur-sm z-10 sticky top-0">
          {isMobileSearchOpen ? (
            <div className="flex items-center w-full gap-3 animate-in fade-in slide-in-from-top-2 duration-200">
               <div className="relative flex-1">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 w-4 h-4" />
                 <input 
                   autoFocus
                   type="text"
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   placeholder="搜索电台..."
                   className="w-full bg-slate-900 border border-slate-800 rounded-full pl-10 pr-8 py-2 text-sm text-slate-300 focus:outline-none focus:border-violet-500 focus:ring-1 focus:ring-violet-500"
                 />
                 {searchQuery && (
                     <button 
                       onClick={() => setSearchQuery('')}
                       className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white"
                     >
                       <X size={14} />
                     </button>
                   )}
               </div>
               <button 
                 onClick={() => { setIsMobileSearchOpen(false); setSearchQuery(''); }}
                 className="text-slate-400 text-sm font-medium whitespace-nowrap"
               >
                 取消
               </button>
            </div>
          ) : (
            <>
              <div className="flex items-center gap-4">
                {/* Show Logo on mobile since Sidebar is hidden */}
                <div className="md:hidden flex items-center gap-2">
                    <div className="w-8 h-8 bg-gradient-to-tr from-violet-500 to-fuchsia-500 rounded-lg flex items-center justify-center">
                        {/* Simple Radio Icon */}
                        <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5.636 18.364a9 9 0 010-12.728m12.728 0a9 9 0 010 12.728m-9.9-2.829a5 5 0 010-7.07m7.072 0a5 5 0 010 7.07M9 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                    </div>
                    <span className="font-bold text-lg">RadioZen</span>
                </div>

                <div className="relative hidden sm:block">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 w-4 h-4" />
                  <input 
                    type="text" 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="搜索电台、节目..." 
                    className="bg-slate-900 border border-slate-800 rounded-full pl-10 pr-8 py-2 text-sm text-slate-300 focus:outline-none focus:border-violet-500 focus:ring-1 focus:ring-violet-500 w-64 transition-all"
                  />
                  {searchQuery && (
                    <button 
                      onClick={() => setSearchQuery('')}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white"
                    >
                      <X size={14} />
                    </button>
                  )}
                </div>
              </div>
              <div className="flex items-center gap-4">
                 <button 
                    onClick={() => setIsMobileSearchOpen(true)}
                    className="sm:hidden text-slate-400 hover:text-white transition-colors"
                 >
                   <Search size={20} />
                 </button>

                 <button className="relative text-slate-400 hover:text-white transition-colors">
                   <Bell size={20} />
                   <span className="absolute top-0 right-0 w-2 h-2 bg-red-500 rounded-full"></span>
                 </button>
                 <button 
                  onClick={() => setShowMobileSidebar(true)}
                  className="md:hidden w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center border border-slate-700"
                 >
                   <Menu size={18} />
                 </button>
                 <div 
                   className="hidden md:block w-8 h-8 rounded-full bg-slate-700 overflow-hidden border border-slate-600 cursor-pointer"
                   onClick={() => setActiveTab('profile')}
                 >
                   <img src="https://picsum.photos/100/100" alt="User" />
                 </div>
              </div>
            </>
          )}
        </header>

        {/* Scrollable Area */}
        <main className="flex-1 overflow-y-auto p-4 md:p-6 pb-32 md:pb-32 scrollbar-hide">
          {renderContent()}
        </main>

        {/* Playlist Sidebar (Overlay) */}
        <Playlist 
          isOpen={showPlaylist}
          onClose={() => setShowPlaylist(false)}
          playlist={playlist}
          currentStation={currentStation}
          onPlay={(s) => handlePlayStation(s, 'playlist')}
          onRemove={handleRemoveFromPlaylist}
          isPlaying={isPlaying}
        />

        {/* Player Bar (Mini Player on Mobile) */}
        <PlayerBar 
          currentStation={currentStation}
          isPlaying={isPlaying}
          onTogglePlay={() => setIsPlaying(!isPlaying)}
          volume={volume}
          onVolumeChange={setVolume}
          isMuted={isMuted}
          onToggleMute={() => setIsMuted(!isMuted)}
          onNext={handleNext}
          onPrev={handlePrev}
          togglePlaylist={() => setShowPlaylist(!showPlaylist)}
          showPlaylist={showPlaylist}
          onOpenFullPlayer={() => setShowFullPlayer(true)}
        />

        {/* Bottom Nav (Mobile Only) */}
        <BottomNav activeTab={activeTab} setActiveTab={handleTabChange} />

        {/* Full Screen Player (Mobile Only) */}
        {showFullPlayer && (
          <MobileFullPlayer 
            station={currentStation}
            isPlaying={isPlaying}
            onTogglePlay={() => setIsPlaying(!isPlaying)}
            onClose={() => setShowFullPlayer(false)}
            onNext={handleNext}
            onPrev={handlePrev}
            volume={volume}
            onVolumeChange={setVolume}
            onTogglePlaylist={() => setShowPlaylist(!showPlaylist)}
          />
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import Hls from 'hls.js';
import { Sidebar } from './components/Sidebar';
import { StationCard } from './components/StationCard';
import { PlayerBar } from './components/PlayerBar';
import { Playlist } from './components/Playlist';
import { BottomNav } from './components/BottomNav';
import { MobileFullPlayer } from './components/MobileFullPlayer';
import { StationDetail } from './components/StationDetail';
import { ProfileView } from './components/ProfileView';
import { SettingsView } from './components/SettingsView';
import { STATIONS, CATEGORIES } from './constants';
import { Station } from './types';
import { Search, Bell, Menu, Heart, History, X } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [activeTab, setActiveTab] = useState('discover');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isMobileSearchOpen, setIsMobileSearchOpen] = useState(false);
  const [stations] = useState<Station[]>(STATIONS);

  // Playlist State
  const [playlist, setPlaylist] = useState<Station[]>([]);
  // 'all' means playing from the main list/grid. 'playlist' means playing from the user queue.
  const [playContext, setPlayContext] = useState<'all' | 'playlist'>('all');

  const [currentStation, setCurrentStation] = useState<Station | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.7);
  const [isMuted, setIsMuted] = useState(false);
  const [showPlaylist, setShowPlaylist] = useState(false);
  const [showFullPlayer, setShowFullPlayer] = useState(false);
  const [showMobileSidebar, setShowMobileSidebar] = useState(false);
  const [detailViewStation, setDetailViewStation] = useState<Station | null>(null);
  const [favorites, setFavorites] = useState<string[]>([]);

  // Recent Stations State
  const [recentStationIds, setRecentStationIds] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('recentStations');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load recent stations", e);
      return [];
    }
  });

  // Refs
  const audioRef = useRef<HTMLAudioElement>(null);
  const hlsRef = useRef<Hls | null>(null);
  const retryCount = useRef(0);

  // Effect: Volume control
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  // Effect: Switch to discover tab when searching
  useEffect(() => {
    if (searchQuery.trim()) {
      setActiveTab('discover');
    }
  }, [searchQuery]);

  // Effect: Handle Source Loading (Normal vs HLS)
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !currentStation) return;

    const src = currentStation.streamUrl;
    const isM3u8 = src.includes('.m3u8') || src.includes('application/x-mpegurl');

    // Clean up previous HLS instance
    if (hlsRef.current) {
      hlsRef.current.destroy();
      hlsRef.current = null;
      retryCount.current = 0; // Reset retry count on source change
    }

    if (isM3u8 && Hls.isSupported()) {
      const hls = new Hls({
        enableWorker: true,
        lowLatencyMode: true,
        // Increase timeout settings for slow connections
        manifestLoadingTimeOut: 20000,
        manifestLoadingMaxRetry: 3,
        levelLoadingTimeOut: 20000,
        levelLoadingMaxRetry: 3,
      });
      hlsRef.current = hls;

      hls.loadSource(src);
      hls.attachMedia(audio);

      hls.on(Hls.Events.MANIFEST_PARSED, () => {
        retryCount.current = 0; // Reset retry count on successful load
        if (isPlaying) {
          const playPromise = audio.play();
          if (playPromise !== undefined) {
             playPromise.catch(error => {
                if (error.name === 'AbortError') return;
                console.error("HLS Auto-play failed:", error);
                setIsPlaying(false);
             });
          }
        }
      });

      hls.on(Hls.Events.ERROR, (event, data) => {
        if (data.fatal) {
          switch (data.type) {
            case Hls.ErrorTypes.NETWORK_ERROR:
              console.error(`HLS Network error: ${data.details}`, data);
              // Try to recover network error with limit
              if (retryCount.current < 3) {
                retryCount.current++;
                console.log(`Attempting to recover from network error (attempt ${retryCount.current}/3)...`);
                hls.startLoad();
              } else {
                console.error("HLS Network error: Max retries reached. Stopping playback.");
                hls.destroy();
                setIsPlaying(false);
              }
              break;
            case Hls.ErrorTypes.MEDIA_ERROR:
              console.warn("HLS Media error, recovering...");
              hls.recoverMediaError();
              break;
            default:
              console.error("HLS Fatal error, destroying...", data);
              hls.destroy();
              setIsPlaying(false);
              break;
          }
        } else {
            // Non-fatal errors (often minor network hiccups)
            if (data.type === Hls.ErrorTypes.NETWORK_ERROR) {
                 console.log(`HLS non-fatal network error: ${data.details}`);
            }
        }
      });
    } else {
      // Native Audio (MP3 or Native HLS on Safari)
      audio.src = src;
      audio.load();
      if (isPlaying) {
        const playPromise = audio.play();
        if (playPromise !== undefined) {
           playPromise.catch(error => {
              if (error.name === 'AbortError') return;
              console.error("Playback failed:", error);
              setIsPlaying(false);
           });
        }
      }
    }

    // Cleanup when component unmounts or station changes
    return () => {
      if (hlsRef.current) {
        hlsRef.current.destroy();
        hlsRef.current = null;
      }
    };
  }, [currentStation?.id]); // Only change source if station ID changes

  // Effect: Handle Play/Pause toggling
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !currentStation) return;

    if (isPlaying) {
      if (audio.paused) {
        const playPromise = audio.play();
        if (playPromise !== undefined) {
          playPromise.catch(error => {
            if (error.name === 'AbortError') return;
            console.error("Play toggle failed:", error);
          });
        }
      }
    } else {
      if (!audio.paused) {
        audio.pause();
      }
    }
  }, [isPlaying]);


  // --- Handlers ---

  const addToRecent = (station: Station) => {
    setRecentStationIds(prev => {
      const newRecents = [station.id, ...prev.filter(id => id !== station.id)].slice(0, 20);
      try {
        localStorage.setItem('recentStations', JSON.stringify(newRecents));
      } catch (e) {
        console.error("Failed to save recent stations", e);
      }
      return newRecents;
    });
  };

  const handleReorderPlaylist = (fromIndex: number, toIndex: number) => {
    setPlaylist(prev => {
        const newPlaylist = [...prev];
        const [movedItem] = newPlaylist.splice(fromIndex, 1);
        newPlaylist.splice(toIndex, 0, movedItem);
        return newPlaylist;
    });
  };

  const handlePlayStation = (station: Station, context: 'all' | 'playlist' = 'all') => {
    setPlayContext(context);

    if (currentStation?.id === station.id) {
      setIsPlaying(!isPlaying);
    } else {
      setCurrentStation(station);
      setIsPlaying(true);
      addToRecent(station);
    }
  };

  const handleNext = () => {
    if (!currentStation) return;

    let listToUse = stations;
    if (playContext === 'playlist' && playlist.length > 0) {
      listToUse = playlist;
    }

    const currentIndex = listToUse.findIndex(s => s.id === currentStation.id);
    // If not found (e.g. removed from playlist while playing), default to 0
    const nextIndex = currentIndex === -1 ? 0 : (currentIndex + 1) % listToUse.length;

    const nextStation = listToUse[nextIndex];
    setCurrentStation(nextStation);
    setIsPlaying(true);
    addToRecent(nextStation);
  };

  const handlePrev = () => {
    if (!currentStation) return;

    let listToUse = stations;
    if (playContext === 'playlist' && playlist.length > 0) {
      listToUse = playlist;
    }

    const currentIndex = listToUse.findIndex(s => s.id === currentStation.id);
    const prevIndex = currentIndex === -1 ? 0 : (currentIndex - 1 + listToUse.length) % listToUse.length;

    const prevStation = listToUse[prevIndex];
    setCurrentStation(prevStation);
    setIsPlaying(true);
    addToRecent(prevStation);
  };

  // Playlist Management
  const handleAddToPlaylist = (station: Station) => {
    setPlaylist(prev => {
      if (prev.some(s => s.id === station.id)) {
        return prev; 
      }
      return [...prev, station];
    });
    setShowPlaylist(true);
  };

  const handleRemoveFromPlaylist = (id: string) => {
    setPlaylist(prev => prev.filter(s => s.id !== id));
  };


  const handleStationClick = (station: Station) => {
    setDetailViewStation(station);
  };

  const handleBackToDiscover = () => {
    setDetailViewStation(null);
  };

  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    setDetailViewStation(null);
    setShowMobileSidebar(false);
  };

  const handleTagClick = (tag: string) => {
    setSelectedTag(tag);
    setActiveTab('discover');
    setDetailViewStation(null);
    setSearchQuery('');
    setSelectedCategory('all');
  };

  const toggleFavorite = (id: string) => {
    setFavorites(prev => prev.includes(id) ? prev.filter(pid => pid !== id) : [...prev, id]);
  };

  // Derived Data
  const filteredStations = stations.filter(station => {
    // 1. Filter by Category
    if (selectedCategory !== 'all' && station.category !== selectedCategory) return false;

    // 2. Filter by Tag
    if (selectedTag && !station.tags.includes(selectedTag)) return false;

    // 3. Filter by Search Query
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase().trim();
      const matchesName = station.name.toLowerCase().includes(query);
      const matchesDesc = station.description.toLowerCase().includes(query);
      const matchesTags = station.tags.some(tag => tag.toLowerCase().includes(query));

      return matchesName || matchesDesc || matchesTags;
    }

    return true;
  });

  const favoriteStations = stations.filter(s => favorites.includes(s.id));

  const recentStations = recentStationIds
    .map(id => stations.find(s => s.id === id))
    .filter((s): s is Station => !!s);

  // Helper for rendering content based on activeTab
  const renderContent = () => {
    if (detailViewStation) {
      return (
        <StationDetail 
          station={detailViewStation} 
          isPlaying={currentStation?.id === detailViewStation.id && isPlaying}
          onTogglePlay={() => handlePlayStation(detailViewStation, 'all')}
          onAddToPlaylist={handleAddToPlaylist}
          onBack={handleBackToDiscover}
          onTagClick={handleTagClick}
        />
      );
    }

    switch (activeTab) {
      case 'discover':
        return (
            <>
              {/* Hero / Featured - Hide if searching or filtering by tag */}
              {!searchQuery && !selectedTag && (
                <div className="mb-8 p-6 md:p-8 rounded-3xl bg-gradient-to-r from-violet-600 to-indigo-600 text-white relative overflow-hidden shadow-2xl">
                   <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -translate-y-1/2 translate-x-1/4 blur-3xl"></div>
                   <div className="relative z-10 max-w-lg">
                      <span className="inline-block px-3 py-1 bg-white/20 backdrop-blur-md rounded-full text-xs font-bold mb-4 border border-white/10">今日推荐</span>
                      <h2 className="text-3xl md:text-4xl font-bold mb-2">城市晚高峰</h2>
                      <p className="text-violet-100 mb-6 text-sm md:text-lg">最好的音乐陪伴你的归途，实时路况与好歌同行。</p>
                      <button 
                        onClick={() => handlePlayStation(stations[0], 'all')}
                        className="bg-white text-violet-700 px-6 py-3 rounded-full font-bold hover:bg-slate-100 transition-colors flex items-center gap-2 shadow-lg text-sm md:text-base"
                      >
                        <Menu className="w-4 h-4 rotate-90" /> 立即收听
                      </button>
                   </div>
                </div>
              )}

              {/* Categories */}
              <div className="mb-8">
                <div className="flex items-center gap-3 overflow-x-auto pb-2 scrollbar-hide">
                  {CATEGORIES.map(cat => (
                    <button
                      key={cat.id}
                      onClick={() => { setSelectedCategory(cat.id); setSelectedTag(null); }}
                      className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all border ${
                        selectedCategory === cat.id && !selectedTag
                          ? 'bg-white text-slate-900 border-white'
                          : 'bg-slate-900 text-slate-400 border-slate-800 hover:border-slate-600 hover:text-white'
                      }`}
                    >
                      {cat.name}
                    </button>
                  ))}
                </div>
              </div>

              {/* Tag Filter Indicator */}
              {selectedTag && (
                <div className="flex items-center gap-2 mb-6 animate-in fade-in slide-in-from-left-2">
                  <span className="text-slate-400 text-sm">正在浏览标签:</span>
                  <button 
                    onClick={() => setSelectedTag(null)}
                    className="flex items-center gap-1 px-3 py-1 bg-violet-600 text-white rounded-full text-sm font-medium hover:bg-violet-700 transition-colors"
                  >
                    #{selectedTag} <X size={14} />
                  </button>
                </div>
              )}

              {/* Station Grid */}
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-6">
                {filteredStations.map(station => (
                  <StationCard
                    key={station.id}
                    station={station}
                    isPlaying={currentStation?.id === station.id && isPlaying}
                    isCurrent={currentStation?.id === station.id}
                    isFavorite={favorites.includes(station.id)}
                    onPlay={(s) => handlePlayStation(s, 'all')}
                    onClick={handleStationClick}
                    onToggleFavorite={toggleFavorite}
                    onAddToPlaylist={handleAddToPlaylist}
                    onTagClick={handleTagClick}
                  />
                ))}
                {filteredStations.length === 0 && (
                  <div className="col-span-full py-20 text-center text-slate-500">
                    {searchQuery ? (
                        <>
                            <p className="text-lg text-slate-400 mb-2">没有找到与 "{searchQuery}" 相关的电台</p>
                            <button onClick={() => setSearchQuery('')} className="text-violet-400 hover:underline">清除搜索</button>
                        </>
                    ) : selectedTag ? (
                         <>
                            <p className="text-lg text-slate-400 mb-2">没有找到标签为 "#{selectedTag}" 的电台</p>
                            <button onClick={() => setSelectedTag(null)} className="text-violet-400 hover:underline">查看全部</button>
                        </>
                    ) : (
                        "没有找到该分类下的电台"
                    )}
                  </div>
                )}
              </div>
            </>
        );
      case 'favorites':
        return (
            <div className="pb-10">
              <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
                 <Heart className="text-rose-500 fill-rose-500" /> 我的收藏
              </h2>
              {favoriteStations.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-6">
                  {favoriteStations.map(station => (
                    <StationCard
                      key={station.id}
                      station={station}
                      isPlaying={currentStation?.id === station.id && isPlaying}
                      isCurrent={currentStation?.id === station.id}
                      isFavorite={true}
                      onPlay={(s) => handlePlayStation(s, 'all')}
                      onClick={handleStationClick}
                      onToggleFavorite={toggleFavorite}
                      onAddToPlaylist={handleAddToPlaylist}
                      onTagClick={handleTagClick}
                    />
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-20 text-slate-500">
                   <div className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mb-4">
                     <Heart size={32} className="opacity-20" />
                   </div>
                   <p className="text-lg">暂无收藏电台</p>
                   <button onClick={() => setActiveTab('discover')} className="mt-4 px-6 py-2 bg-violet-600/10 text-violet-400 rounded-full text-sm font-medium hover:bg-violet-600/20 transition-colors">
                       去发现更多
                   </button>
                </div>
              )}
            </div>
        );
      case 'recent':
        return (
            <div className="pb-10">
              <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
                 <History className="text-slate-100" /> 最近播放
              </h2>
              {recentStations.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 md:gap-6">
                  {recentStations.map(station => (
                    <StationCard
                      key={station.id}
                      station={station}
                      isPlaying={currentStation?.id === station.id && isPlaying}
                      isCurrent={currentStation?.id === station.id}
                      isFavorite={favorites.includes(station.id)}
                      onPlay={(s) => handlePlayStation(s, 'all')}
                      onClick={handleStationClick}
                      onToggleFavorite={toggleFavorite}
                      onAddToPlaylist={handleAddToPlaylist}
                      onTagClick={handleTagClick}
                    />
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-20 text-slate-500">
                   <div className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mb-4">
                     <History size={32} className="opacity-20" />
                   </div>
                   <p className="text-lg">暂无最近播放记录</p>
                   <button onClick={() => setActiveTab('discover')} className="mt-4 px-6 py-2 bg-violet-600/10 text-violet-400 rounded-full text-sm font-medium hover:bg-violet-600/20 transition-colors">
                       去听听看
                   </button>
                </div>
              )}
            </div>
        );
      case 'profile':
        return <ProfileView onNavigate={setActiveTab} />;
      case 'settings':
        return <SettingsView />;
      default:
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-500">
              <div className="bg-slate-900 p-6 rounded-full mb-4">
                <Menu size={48} className="opacity-20" />
              </div>
              <h3 className="text-xl font-medium text-slate-400 mb-2">即将推出</h3>
              <p>该功能正在开发中...</p>
            </div>
        );
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden font-sans">
      {/* Hidden Audio Element - Remove src prop as it's handled in useEffect */}
      <audio 
        ref={audioRef} 
        onEnded={handleNext} // Auto-play next when stream/track ends (mostly for mp3 files)
        onError={(e) => {
            console.error("Native Audio Error", e);
            if (!hlsRef.current) {
               setIsPlaying(false);
            }
        }}
      />

      {/* Mobile Sidebar (Optional/Secondary) */}
      {showMobileSidebar && (
        <div className="fixed inset-0 bg-black/80 z-50 md:hidden" onClick={() => setShowMobileSidebar(false)}>
           <div className="w-64 h-full bg-slate-900" onClick={e => e.stopPropagation()}>
             <Sidebar activeTab={activeTab} setActiveTab={handleTabChange} />
           </div>
        </div>
      )}

      {/* Sidebar (Desktop) */}
      <div className="hidden md:block fixed inset-y-0 left-0 z-40">
        <Sidebar activeTab={activeTab} setActiveTab={handleTabChange} />
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative md:pl-64">
        {/* Header */}
        <header className="flex items-center justify-between px-4 md:px-6 py-4 bg-slate-950/50 backdrop-blur-sm z-10 sticky top-0">
          {isMobileSearchOpen ? (
            <div className="flex items-center w-full gap-3 animate-in fade-in slide-in-from-top-2 duration-200">
               <div className="relative flex-1">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 w-4 h-4" />
                 <input 
                   autoFocus
                   type="text"
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   placeholder="搜索电台..."
                   className="w-full bg-slate-900 border border-slate-800 rounded-full pl-10 pr-8 py-2 text-sm text-slate-300 focus:outline-none focus:border-violet-500 focus:ring-1 focus:ring-violet-500"
                 />
                 {searchQuery && (
                     <button 
                       onClick={() => setSearchQuery('')}
                       className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white"
                     >
                       <X size={14} />
                     </button>
                   )}
               </div>
               <button 
                 onClick={() => { setIsMobileSearchOpen(false); setSearchQuery(''); }}
                 className="text-slate-400 text-sm font-medium whitespace-nowrap"
               >
                 取消
               </button>
            </div>
          ) : (
            <>
              <div className="flex items-center gap-4">
                {/* Show Logo on mobile since Sidebar is hidden */}
                <div className="md:hidden flex items-center gap-2">
                    <div className="w-8 h-8 bg-gradient-to-tr from-violet-500 to-fuchsia-500 rounded-lg flex items-center justify-center">
                        {/* Simple Radio Icon */}
                        <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5.636 18.364a9 9 0 010-12.728m12.728 0a9 9 0 010 12.728m-9.9-2.829a5 5 0 010-7.07m7.072 0a5 5 0 010 7.07M9 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                    </div>
                    <span className="font-bold text-lg">RadioZen</span>
                </div>

                <div className="relative hidden sm:block">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 w-4 h-4" />
                  <input 
                    type="text" 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="搜索电台、节目..." 
                    className="bg-slate-900 border border-slate-800 rounded-full pl-10 pr-8 py-2 text-sm text-slate-300 focus:outline-none focus:border-violet-500 focus:ring-1 focus:ring-violet-500 w-64 transition-all"
                  />
                  {searchQuery && (
                    <button 
                      onClick={() => setSearchQuery('')}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white"
                    >
                      <X size={14} />
                    </button>
                  )}
                </div>
              </div>
              <div className="flex items-center gap-4">
                 <button 
                    onClick={() => setIsMobileSearchOpen(true)}
                    className="sm:hidden text-slate-400 hover:text-white transition-colors"
                 >
                   <Search size={20} />
                 </button>

                 <button className="relative text-slate-400 hover:text-white transition-colors">
                   <Bell size={20} />
                   <span className="absolute top-0 right-0 w-2 h-2 bg-red-500 rounded-full"></span>
                 </button>
                 <button 
                  onClick={() => setShowMobileSidebar(true)}
                  className="md:hidden w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center border border-slate-700"
                 >
                   <Menu size={18} />
                 </button>
                 <div 
                   className="hidden md:block w-8 h-8 rounded-full bg-slate-700 overflow-hidden border border-slate-600 cursor-pointer"
                   onClick={() => setActiveTab('profile')}
                 >
                   <img src="https://picsum.photos/100/100" alt="User" />
                 </div>
              </div>
            </>
          )}
        </header>

        {/* Scrollable Area */}
        <main className="flex-1 overflow-y-auto p-4 md:p-6 pb-32 md:pb-32 scrollbar-hide">
          {renderContent()}
        </main>

        {/* Playlist Sidebar (Overlay) */}
        <Playlist 
          isOpen={showPlaylist}
          onClose={() => setShowPlaylist(false)}
          playlist={playlist}
          currentStation={currentStation}
          onPlay={(s) => handlePlayStation(s, 'playlist')}
          onRemove={handleRemoveFromPlaylist}
          onReorder={handleReorderPlaylist}
          isPlaying={isPlaying}
        />

        {/* Player Bar (Mini Player on Mobile) */}
        <PlayerBar 
          currentStation={currentStation}
          isPlaying={isPlaying}
          onTogglePlay={() => setIsPlaying(!isPlaying)}
          volume={volume}
          onVolumeChange={setVolume}
          isMuted={isMuted}
          onToggleMute={() => setIsMuted(!isMuted)}
          onNext={handleNext}
          onPrev={handlePrev}
          togglePlaylist={() => setShowPlaylist(!showPlaylist)}
          showPlaylist={showPlaylist}
          onOpenFullPlayer={() => setShowFullPlayer(true)}
        />

        {/* Bottom Nav (Mobile Only) */}
        <BottomNav activeTab={activeTab} setActiveTab={handleTabChange} />

        {/* Full Screen Player (Mobile Only) */}
        {showFullPlayer && (
          <MobileFullPlayer 
            station={currentStation}
            isPlaying={isPlaying}
            onTogglePlay={() => setIsPlaying(!isPlaying)}
            onClose={() => setShowFullPlayer(false)}
            onNext={handleNext}
            onPrev={handlePrev}
            volume={volume}
            onVolumeChange={setVolume}
            onTogglePlaylist={() => setShowPlaylist(!showPlaylist)}
          />
        )}
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { X, Play, BarChart2, Trash2, ListMusic } from 'lucide-react';
import { Station } from '../types';

