  isOpen: boolean;
  onClose: () => void;
  playlist: Station[];
  currentStation: Station | null;
  onPlay: (station: Station) => void;
  onRemove: (id: string) => void;
  onReorder?: (fromIndex: number, toIndex: number) => void;
  isPlaying: boolean;
}

export const Playlist: React.FC<PlaylistProps> = ({ 
  isOpen, 
  onClose, 
  playlist, 
  currentStation, 
  onPlay,
  onRemove,
  onReorder,
  isPlaying 
}) => {
  return (
    <div 
      className={`fixed inset-y-0 right-0 w-full md:w-96 bg-slate-900 border-l border-slate-800 shadow-2xl transform transition-transform duration-300 ease-in-out z-[70] ${
        isOpen ? 'translate-x-0' : 'translate-x-full'
