                    >
                      <X size={14} />
                    </button>
                  )}
                </div>
              </div>
              <div className="flex items-center gap-4">
                 <button 
                    onClick={() => setIsMobileSearchOpen(true)}
                    className="sm:hidden text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors"
                 >
