const CACHE_NAME = 'radiozen-v4';
const ASSETS_TO_CACHE = [
  './',
  './index.html',
  './manifest.json'
];

self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS_TO_CACHE.map(url => new Request(url, {cache: 'reload'})));
    })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            return caches.delete(cacheName);
          }
        })
      );
    })
  );
  self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // Ignore audio streams
  if (url.pathname.endsWith('.m3u8') || url.pathname.endsWith('.mp3') || url.pathname.endsWith('.aac')) {
    return;
  }

  // Navigation: Network -> Cache -> Fallback to index.html
  if (event.request.mode === 'navigate') {
    event.respondWith(
      (async () => {
        try {
          const networkResponse = await fetch(event.request);
          if (networkResponse && networkResponse.status === 200) {
            return networkResponse;
          }
          throw new Error('Network error');
        } catch (error) {
          const cache = await caches.open(CACHE_NAME);
          // First try exact match
          const cachedResponse = await cache.match(event.request);
          if (cachedResponse) return cachedResponse;

          // Fallback to index.html for SPA routing
          const fallbackResponse = await cache.match('./index.html');
          if (fallbackResponse) return fallbackResponse;

          // If cache key was stored as absolute URL in some environments
          const fallbackRoot = await cache.match('./');
          if (fallbackRoot) return fallbackRoot;

          return null;
        }
      })()
    );
    return;
  }

  // Assets: Stale-While-Revalidate
  event.respondWith(
    caches.match(event.request, { ignoreSearch: true }).then((cachedResponse) => {
      const fetchPromise = fetch(event.request).then((networkResponse) => {
        if (networkResponse && networkResponse.status === 200) {
          const responseToCache = networkResponse.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(event.request, responseToCache);
          });
        }
        return networkResponse;
      }).catch(() => {});

      return cachedResponse || fetchPromise;
    })
  );
});

